// ─── JIRA PROXY — Bot Discord ────────────────────────────────────────────────
// Recebe chamadas do bot Discord e repassa para o Jira.
// O bot usa este proxy porque chamadas diretas ao Jira apresentam timeout
// em alguns ambientes de nuvem.
//
// PREENCHA AS CREDENCIAIS ABAIXO:
// ────────────────────────────────────────────────────────────────────────────

const JIRA_DOMAIN  = 'sua-empresa.atlassian.net';
const JIRA_EMAIL   = 'seu@email.com';
const JIRA_TOKEN   = 'SEU_JIRA_TOKEN';
const JIRA_PROJECT = 'SCRUM';  // prefixo das issues (ex: SCRUM, DEV, API)
const JIRA_BOARD   = 1;        // ID do board
const JIRA_SPRINT_ID = 1;      // ID da sprint ativa

// Confluence (opcional — para comandos /confluence, /user-stories etc.)
const CONFLUENCE_DOMAIN = 'sua-empresa.atlassian.net';
const CONFLUENCE_SPACE  = 'SEUSPACE';

// ─── NÃO ALTERE ABAIXO DESTA LINHA ──────────────────────────────────────────

const jiraAuth    = 'Basic ' + Buffer.from(JIRA_EMAIL + ':' + JIRA_TOKEN).toString('base64');
const jiraHeaders = { 'Authorization': jiraAuth, 'Accept': 'application/json' };

const tipo  = $input.first().json.query?.tipo || '';
const extra = $input.first().json.query?.extra || '';

const jiraGet = async (url) => {
  try {
    const r = await this.helpers.httpRequest({
      method: 'GET', url, headers: jiraHeaders,
      returnFullResponse: true, ignoreHttpStatusErrors: true,
    });
    const body = typeof r.body === 'string' ? JSON.parse(r.body) : (r.body ?? r);
    return body || {};
  } catch(e) { return { __error: e.message }; }
};

// ─── ROTEAMENTO POR TIPO ─────────────────────────────────────────────────────

if (tipo === 'sprint') {
  const jql = encodeURIComponent(`project=${JIRA_PROJECT} AND sprint=${JIRA_SPRINT_ID} ORDER BY status ASC`);
  const res = await jiraGet(`https://${JIRA_DOMAIN}/rest/api/3/search?jql=${jql}&maxResults=100&fields=summary,status,assignee,labels,updated`);
  return [{ json: { issues: res.issues || [] } }];
}

if (tipo === 'backlog') {
  const jql = encodeURIComponent(`project=${JIRA_PROJECT} AND sprint is EMPTY AND issuetype=Story ORDER BY created DESC`);
  const res = await jiraGet(`https://${JIRA_DOMAIN}/rest/api/3/search?jql=${jql}&maxResults=50&fields=summary,issuetype`);
  return [{ json: { issues: res.issues || [] } }];
}

if (tipo === 'semsprint') {
  const jql = encodeURIComponent(`project=${JIRA_PROJECT} AND sprint is EMPTY ORDER BY created DESC`);
  const res = await jiraGet(`https://${JIRA_DOMAIN}/rest/api/3/search?jql=${jql}&maxResults=50&fields=summary,status,assignee`);
  return [{ json: { issues: res.issues || [] } }];
}

if (tipo === 'devops') {
  const jql = encodeURIComponent(`project=${JIRA_PROJECT} AND labels=devops ORDER BY status ASC`);
  const res = await jiraGet(`https://${JIRA_DOMAIN}/rest/api/3/search?jql=${jql}&maxResults=50&fields=summary,status,assignee,labels,updated`);
  return [{ json: { issues: res.issues || [] } }];
}

if (tipo === 'changelog' && extra) {
  const issueKey = extra.includes('-') ? extra : `${JIRA_PROJECT}-${extra}`;
  const [issue, changelog] = await Promise.all([
    jiraGet(`https://${JIRA_DOMAIN}/rest/api/3/issue/${issueKey}?fields=summary,status,assignee,created,updated`),
    jiraGet(`https://${JIRA_DOMAIN}/rest/api/3/issue/${issueKey}/changelog?maxResults=50`),
  ]);
  return [{ json: { issue, changelog } }];
}

// Confluence — páginas de documentação
if (tipo.startsWith('confluence-')) {
  // Implemente conforme suas páginas do Confluence
  // Retorne { markdown: '...', url: '...', version: N }
  return [{ json: { __error: 'Confluence não configurado' } }];
}

return [{ json: { __error: `Tipo desconhecido: ${tipo}` } }];
